parallel --colsep , --header : CUDA_VISIBLE_DEVICES=0,1,2,3,4 'python src/dafm/main_optuna.py +experiment=Lorenz63Spantini2022 filter=EnsembleScoreFilter filter/prob_path=Bao2024EnsembleScoreMatching filter.sampling_time_step_count=10 setting.observe_every_n_time_steps={observe_every_n_time_steps} setting.reference_filter={reference_filter} "optuna_trial_params=[{override:filter.prob_path.epsilon_alpha,type:float,min:1e-2,max:1,log:false},{override:filter.prob_path.epsilon_beta,type:float,min:1e-3,max:.3,log:false}]"' ::: $(duckdb runs.sqlite -c "copy (with observe_ids as (select id from ObserveIdentity), da_setting_candidates as (select DataAssimilationSetting from DataAssimilationSetting__Observe group by DataAssimilationSetting having sum(Observe in (select id from observe_ids)) = (select count(*) from observe_ids)) select alt_id as reference_filter, observe_every_n_time_steps from Conf join da_setting_candidates using (DataAssimilationSetting) join DataAssimilationSetting on Conf.DataAssimilationSetting = DataAssimilationSetting.id join DynamicalSystemImpl on DataAssimilationSetting.DynamicalSystemImpl = DynamicalSystemImpl.id join Lorenz63 on DynamicalSystemImpl.DynamicalSystem = Lorenz63.id join BootstrapParticleFilter on Conf.Filter = BootstrapParticleFilter.id where DynamicalSystemImpl.rng_seed = 2376999025 and observe_every_n_time_steps in (2, 4, 8, 16) and save_ensemble_stats) to '/dev/stdout';")

parallel --colsep , --header : CUDA_VISIBLE_DEVICES=0,1,2,3,4 'python src/dafm/main_optuna.py +experiment=Lorenz63Spantini2022 filter=EnsembleScoreFilter filter/prob_path=Bao2024EnsembleScoreMatching filter.sampling_time_step_count=10 setting.observe_every_n_time_steps={observe_every_n_time_steps} setting.reference_filter={reference_filter} "setting.observes=[{_target_:conf.observe.ObserveATan,order:0}]" setting.obs_noise_std=.1 "optuna_trial_params=[{override:filter.prob_path.epsilon_alpha,type:float,min:1e-2,max:1,log:false},{override:filter.prob_path.epsilon_beta,type:float,min:1e-3,max:.3,log:false}]"' ::: $(duckdb runs.sqlite -c "copy (with observe_ids as (select id from ObserveATan), da_setting_candidates as (select DataAssimilationSetting from DataAssimilationSetting__Observe group by DataAssimilationSetting having sum(Observe in (select id from observe_ids)) = (select count(*) from observe_ids)) select alt_id as reference_filter, observe_every_n_time_steps from Conf join da_setting_candidates using (DataAssimilationSetting) join DataAssimilationSetting on Conf.DataAssimilationSetting = DataAssimilationSetting.id join DynamicalSystemImpl on DataAssimilationSetting.DynamicalSystemImpl = DynamicalSystemImpl.id join Lorenz63 on DynamicalSystemImpl.DynamicalSystem = Lorenz63.id join BootstrapParticleFilter on Conf.Filter = BootstrapParticleFilter.id where DynamicalSystemImpl.rng_seed = 2376999025 and observe_every_n_time_steps in (2, 4, 8, 16) and save_ensemble_stats and obs_noise_std = .1) to '/dev/stdout';")
